# 2-state MDP: s0 (non-terminal), s1 (absorbing)
S = ['s0','s1']
A = ['a0','a1']
P = {
    's0': {'a0': {'s0':0.0,'s1':1.0}, 'a1': {'s0':1.0,'s1':0.0}},
    's1': {'a0': {'s0':0.0,'s1':1.0}, 'a1': {'s0':0.0,'s1':1.0}}
}
R = {'s0': {'a0': 10.0, 'a1': 0.0}, 's1': {'a0': 0.0, 'a1': 0.0}}
V, pi = value_iteration(S, A, P, R, gamma=0.9)
assert pi['s0'] == 'a0', 'From s0, a0 gives reward 10 and goes to s1'
assert V['s0'] > V['s1']  # s0 has value because a0 yields reward
print('PASS')
